#include<bits/stdc++.h>
using namespace std;
long long pow10(int x){
	long long ans=1;
	for(long long i=1;i<=x;i++){
		ans*=10;
	}
	return ans;
}
long long die(long long x, long long d) {
	if (x == 0) {
		return 0;
	}
	return 10 * die(x - 1, d) + pow10(x - 1); 
}
int main() {
	string s;
	long long x, y, ans = 0;
	cin >> x >> y;
	for (int xx = 0; xx <= 9; xx++) {
		s = to_string(y);
		ans = 0;
		for (long long i = 0; i < s.size(); i++) {
			if (xx == 0) {
				ans += ((s[i] - '0') * die(s.size() - i - 1, 1));
			} else {
				if (s[i] - '0' < xx) ans += ((s[i] - '0') * die(s.size() - i - 1, 0));
				else if (s[i] - '0' > xx)ans += (((s[i] - '0') * die(s.size() - i - 1, 0)) + pow10(s.size() - i - 1));
				else {
					long long num = 0;
					for (int j = i + 1; j < s.size(); j++)
						num = num * 10 + s[j] - '0';
					ans += (s[i] - '0') * die(s.size() - i - 1, 0) + num + 1;
				}
			}
		}
		s = to_string(x-1);
		for (long long i = 0; i < s.size(); i++) {
			if (xx == 0) {
				ans -= ((s[i] - '0') * die(s.size() - i - 1, 1));
			} else {
				if (s[i] - '0' < xx) ans -= ((s[i] - '0') * die(s.size() - i - 1, 0));
				else if (s[i] - '0' > xx)ans -= (((s[i] - '0') * die(s.size() - i - 1, 0)) +  pow10(s.size() - i - 1));
				else {
					long long num = 0;
					for (int j = i + 1; j < s.size(); j++)
						num = num * 10 + s[j] - '0';
					ans -= (s[i] - '0') * die(s.size() - i - 1, 0) + num + 1;
				}
			}
		}
		cout << ans << " ";
	}
}
